#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=2e3+5;
int n,a[MAXN],sum[MAXN],f[MAXN][MAXN];
int main(void){
	//freopen("Farmer_John.in","r",stdin);
	//freopen("Farmer_John.out","w",stdout);
	//input
    n=read();
    for(int i=1;i<=n;++i)
    {
        a[i]=read();
        f[i][i]=a[i]*n;
    }
    //interval DP
    for(int len=2;len<=n;++len)//lenght
    {
        for(int l=1;l<=n-len+1;++l)//left
        {
            int r=l+len-1;//right
            f[l][r]=max(f[l][r-1]+a[r]*(n-len+1),f[l+1][r]+a[l]*(n-len+1));
        }
    }
    //print
    write(f[1][n]);
	return false;
}
